The reference solution of that problem in Javascript is 
function solve(nums) {
    const abs_nums = nums.map(x => Math.abs(x));
    abs_nums.sort((a, b) => a - b);
    let count = 0;
    const n = abs_nums.length;
    for (let i = 0; i < n; i++) {
        const target = 2 * abs_nums[i];
        let left = i + 1;
        let right = n - 1;
        let j = -1;
        while (left <= right) {
            const mid = Math.floor((left + right) / 2);
            if (abs_nums[mid] <= target) {
                j = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        if (j !== -1) {
            count += j - i;
        }
    }
    return count;
}

